import type { DurationObservation } from './duration-smoothing'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, resolve } from 'pathe'

export type DurationHistory = Record<string, DurationObservation[]>

function observations(value: unknown): DurationObservation[] {
  if (typeof value === 'number') { return [{ duration: value, recordedAt: 0 }] }
  if (!value || typeof value !== 'object') { return [] }
  const entries = 'observations' in value ? (value as { observations: unknown }).observations : [value]
  if (!Array.isArray(entries)) { return [] }
  return entries.filter((entry): entry is DurationObservation => !!entry && typeof entry === 'object' && Number.isFinite((entry as DurationObservation).duration) && Number.isFinite((entry as DurationObservation).recordedAt))
}

export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
  try {
    const data = JSON.parse(await readFile(resolve(root, path), 'utf8')) as Record<string, unknown>
    if (!data || typeof data !== 'object' || Array.isArray(data)) { return null }
    const cutoff = Date.now() - ttl
    return Object.fromEntries(Object.entries(data).map(([key, value]) => [key, observations(value).filter(value => !ttl || value.recordedAt === 0 || value.recordedAt >= cutoff)]))
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(root: string, path: string, existing: DurationHistory | null, durations: Record<string, number>, maxRuns: number, ttl: number): Promise<void> {
  const cutoff = Date.now() - ttl
  const history: DurationHistory = { ...(existing || {}) }
  const recordedAt = Date.now()
  for (const [file, duration] of Object.entries(durations)) {
    const previous = (history[file] || []).filter(value => !ttl || value.recordedAt === 0 || value.recordedAt >= cutoff)
